    question: "Demonstrate encapsulation by creating a class 'BankAccount' with private balance and public methods.",
    mathSolution: "Encapsulation hides internal state, exposes controlled access.",
    codeSolution: "using System;\n\nclass BankAccount\n{\n    private double balance;\n    \n    public void Deposit(double amount)\n    {\n        if (amount > 0)\n        {\n            balance += amount;\n            Console.WriteLine($\"Deposited: ${amount}\");\n        }\n    }\n    \n    public void Withdraw(double amount)\n    {\n        if (amount > 0 && amount <= balance)\n        {\n            balance -= amount;\n            Console.WriteLine($\"Withdrawn: ${amount}\");\n        }\n        else\n        {\n            Console.WriteLine(\"Insufficient balance\");\n        }\n    }\n    \n    public double GetBalance()\n    {\n        return balance;\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        BankAccount account = new BankAccount();\n        account.Deposit(1000);\n        account.Withdraw(300);\n        Console.WriteLine($\"Current balance: ${account.GetBalance()}\");\n    }\n}",
    hint: "Private fields + public methods = encapsulation.",
