    codeSolution: "using System;\n\nclass BaseClass\n{\n    private int privateField = 10;\n    protected int protectedField = 20;\n    public int publicField = 30;\n    \n    public void ShowAccess()\n    {\n        Console.WriteLine($\"Private: {privateField}\");\n        Console.WriteLine($\"Protected: {protectedField}\");\n        Console.WriteLine($\"Public: {publicField}\");\n    }\n}\n\nclass DerivedClass : BaseClass\n{\n    public void AccessProtected()\n    {\n        // Console.WriteLine(privateField); // Error: cannot access\n        Console.WriteLine($\"Accessing protected field: {protectedField}\");\n        Console.WriteLine($\"Accessing public field: {publicField}\");\n        \n        protectedField = 50; // Can modify protected field\n        Console.WriteLine($\"Modified protected field: {protectedField}\");\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        DerivedClass derived = new DerivedClass();\n        derived.AccessProtected();\n        derived.ShowAccess();\n    }\n}",
