    codeSolution: "using System;\n\n// Deep inheritance (not recommended)\n// class Animal { }\n// class Mammal : Animal { }\n// class Canine : Mammal { }\n// class Dog : Canine { }\n// class Labrador : Dog { }\n\n// Better: Composition over deep inheritance\ninterface IBark\n{\n    void Bark();\n}\n\ninterface IRun\n{\n    void Run();\n}\n\nclass BarkBehavior : IBark\n{\n    public void Bark() => Console.WriteLine(\"Woof! Woof!\");\n}\n\nclass RunBehavior : IRun\n{\n    public void Run() => Console.WriteLine(\"Running fast!\");\n}\n\nclass Dog\n{\n    private readonly IBark barkBehavior;\n    private readonly IRun runBehavior;\n    \n    public Dog()\n    {\n        barkBehavior = new BarkBehavior();\n        runBehavior = new RunBehavior();\n    }\n    \n    public void Bark() => barkBehavior.Bark();\n    public void Run() => runBehavior.Run();\n}\n\nclass Program\n{\n    static void Main()\n    {\n        Dog dog = new Dog();\n        dog.Bark();\n        dog.Run();\n        Console.WriteLine(\"Composition provides more flexibility than deep inheritance\");\n    }\n}",
