    question: "Demonstrate virtual methods vs abstract methods.",
    mathSolution: "Virtual has optional override, abstract must be overridden.",
    codeSolution: "using System;\n\nabstract class Shape\n{\n    public virtual void Display()\n    {\n        Console.WriteLine(\"This is a shape\");\n    }\n    \n    public abstract double GetArea(); // Must be overridden\n    \n    public virtual double GetPerimeter() // Can be overridden\n    {\n        return 0;\n    }\n}\n\nclass Circle : Shape\n{\n    public double Radius { get; set; }\n    \n    public Circle(double radius)\n    {\n        Radius = radius;\n    }\n    \n    public override double GetArea()\n    {\n        return Math.PI * Radius * Radius;\n    }\n    \n    public override double GetPerimeter()\n    {\n        return 2 * Math.PI * Radius;\n    }\n    \n    // Optional: not overriding Display() uses base implementation\n}\n\nclass Program\n{\n    static void Main()\n    {\n        Circle circle = new Circle(5);\n        circle.Display(); // Uses base class implementation\n        Console.WriteLine($\"Area: {circle.GetArea():F2}\");\n        Console.WriteLine($\"Perimeter: {circle.GetPerimeter():F2}\");\n    }\n}",
    hint: "Abstract methods have no body, virtual methods have default implementation.",
