    question: "Demonstrate explicit interface implementation to resolve conflicts.",
    mathSolution: "Explicit implementation for interfaces with same method name.",
    codeSolution: "using System;\n\ninterface IPrintable\n{\n    void Print();\n}\n\ninterface IScannable\n{\n    void Print();\n}\n\nclass MultiFunctionPrinter : IPrintable, IScannable\n{\n    // Explicit implementation for IPrintable\n    void IPrintable.Print()\n    {\n        Console.WriteLine(\"Printing document\");\n    }\n    \n    // Explicit implementation for IScannable\n    void IScannable.Print()\n    {\n        Console.WriteLine(\"Scanning document\");\n    }\n    \n    // Optional: Public method to access both\n    public void PrintBoth()\n    {\n        ((IPrintable)this).Print();\n        ((IScannable)this).Print();\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        MultiFunctionPrinter printer = new MultiFunctionPrinter();\n        printer.PrintBoth();\n        \n        // Access through interface reference\n        IPrintable printable = printer;\n        printable.Print(); // Prints\n        \n        IScannable scannable = printer;\n        scannable.Print(); // Scans\n    }\n}",
    hint: "Explicit implementation uses InterfaceName.MethodName syntax.",
