    question: "Demonstrate default interface methods (C# 8.0+).",
    mathSolution: "Interfaces can now provide default implementations.",
    codeSolution: "using System;\n\ninterface ILogger\n{\n    void Log(string message);\n    \n    // Default implementation\n    void LogError(string error)\n    {\n        Log($\"ERROR: {error}\");\n    }\n    \n    void LogWarning(string warning)\n    {\n        Log($\"WARNING: {warning}\");\n    }\n}\n\nclass ConsoleLogger : ILogger\n{\n    public void Log(string message)\n    {\n        Console.WriteLine($\"[LOG] {DateTime.Now}: {message}\");\n    }\n    \n    // Can override default methods\n    public void LogError(string error)\n    {\n        Console.WriteLine($\"[CUSTOM ERROR] {error}\");\n    }\n    \n    // LogWarning uses default implementation\n}\n\nclass Program\n{\n    static void Main()\n    {\n        ConsoleLogger logger = new ConsoleLogger();\n        logger.Log(\"Application started\");\n        logger.LogError(\"Something went wrong\");\n        logger.LogWarning(\"Low memory warning\");\n    }\n}",
