    mathSolution: "is for type checking, as for safe casting.",
    codeSolution: "using System;\n\nclass Shape { }\nclass Circle : Shape { public double Radius { get; set; } }\nclass Rectangle : Shape { public double Width { get; set; } }\n\nclass Program\n{\n    static void Main()\n    {\n        Shape[] shapes = { new Circle { Radius = 5 }, new Rectangle { Width = 10 }, new Circle { Radius = 3 } };\n        \n        foreach (Shape shape in shapes)\n        {\n            // Using 'is' operator\n            if (shape is Circle)\n            {\n                Console.WriteLine(\"This is a circle\");\n            }\n            \n            // Using 'as' operator for safe casting\n            Circle circle = shape as Circle;\n            if (circle != null)\n            {\n                Console.WriteLine($\"Circle radius: {circle.Radius}\");\n            }\n            \n            // Pattern matching with 'is'\n            if (shape is Rectangle rect)\n            {\n                Console.WriteLine($\"Rectangle width: {rect.Width}\");\n            }\n        }\n    }\n}",
    hint: "is returns bool, as returns null if cast fails.",
