    codeSolution: "using System;\n\nclass BaseCollection\n{\n    protected string[] items = new string[10];\n    \n    public virtual string this[int index]\n    {\n        get\n        {\n            if (index >= 0 && index < items.Length)\n                return items[index];\n            return null;\n        }\n        set\n        {\n            if (index >= 0 && index < items.Length)\n                items[index] = value;\n        }\n    }\n}\n\nclass ValidatedCollection : BaseCollection\n{\n    public override string this[int index]\n    {\n        get\n        {\n            if (index < 0 || index >= items.Length)\n                throw new IndexOutOfRangeException();\n            return base[index];\n        }\n        set\n        {\n            if (string.IsNullOrWhiteSpace(value))\n                throw new ArgumentException(\"Value cannot be empty\");\n            base[index] = value;\n        }\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        ValidatedCollection collection = new ValidatedCollection();\n        collection[0] = \"Hello\";\n        collection[1] = \"World\";\n        \n        Console.WriteLine($\"Index 0: {collection[0]}\");\n        Console.WriteLine($\"Index 1: {collection[1]}\");\n        \n        try\n        {\n            collection[2] = \"\"; // This will throw exception\n        }\n        catch (Exception ex)\n        {\n            Console.WriteLine($\"Error: {ex.Message}\");\n        }\n    }\n}",
