    codeSolution: "using System;\n\nclass BaseClass\n{\n    public static int staticCounter = 0;\n    \n    public BaseClass()\n    {\n        staticCounter++;\n    }\n}\n\nclass DerivedClass : BaseClass\n{\n    public DerivedClass()\n    {\n        staticCounter++;\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        Console.WriteLine($\"Initial counter: {BaseClass.staticCounter}\");\n        \n        BaseClass b1 = new BaseClass();\n        BaseClass b2 = new BaseClass();\n        DerivedClass d1 = new DerivedClass();\n        \n        Console.WriteLine($\"After creating objects: {BaseClass.staticCounter}\");\n        \n        // Static members are shared\n        // DerivedClass.staticCounter refers to same static field\n        Console.WriteLine($\"Access via derived: {DerivedClass.staticCounter}\");\n    }\n}",
