    codeSolution: "using System;\n\nclass Repository<T>\n{\n    protected T item;\n    \n    public void Store(T item)\n    {\n        this.item = item;\n        Console.WriteLine($\"Stored: {item}\");\n    }\n    \n    public virtual T Retrieve()\n    {\n        return item;\n    }\n}\n\nclass ValidatedRepository<T> : Repository<T> where T : class\n{\n    private bool isValidated;\n    \n    public void Validate()\n    {\n        if (item != null)\n        {\n            isValidated = true;\n            Console.WriteLine(\"Item validated\");\n        }\n    }\n    \n    public override T Retrieve()\n    {\n        if (!isValidated)\n        {\n            Console.WriteLine(\"Warning: Returning unvalidated item\");\n        }\n        return base.Retrieve();\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        ValidatedRepository<string> repo = new ValidatedRepository<string>();\n        repo.Store(\"Hello World\");\n        repo.Validate();\n        string data = repo.Retrieve();\n        Console.WriteLine($\"Retrieved: {data}\");\n    }\n}",
