    codeSolution: "using System;\n\nclass OuterClass\n{\n    protected string outerField = \"Outer field\";\n    \n    public class NestedClass\n    {\n        public void Display()\n        {\n            Console.WriteLine(\"Nested class method\");\n        }\n    }\n    \n    public class InheritedNested : NestedClass\n    {\n        public void ShowInheritance()\n        {\n            Console.WriteLine(\"Nested class inherits from another nested class\");\n        }\n    }\n}\n\nclass DerivedOuter : OuterClass\n{\n    public void AccessOuterProtected()\n    {\n        Console.WriteLine($\"Accessing from derived outer: {outerField}\");\n    }\n    \n    public class DerivedNested : OuterClass.NestedClass\n    {\n        public void NewMethod()\n        {\n            Console.WriteLine(\"Derived nested class method\");\n        }\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        OuterClass.NestedClass nested = new OuterClass.NestedClass();\n        nested.Display();\n        \n        DerivedOuter.DerivedNested derivedNested = new DerivedOuter.DerivedNested();\n        derivedNested.Display();\n        derivedNested.NewMethod();\n        \n        DerivedOuter outer = new DerivedOuter();\n        outer.AccessOuterProtected();\n    }\n}",
