    codeSolution: "using System;\n\nclass Converter\n{\n    public int Convert(int value)\n    {\n        return value;\n    }\n    \n    public long Convert(long value)\n    {\n        return value * 2;\n    }\n    \n    public float Convert(float value)\n    {\n        return value * 1.5f;\n    }\n    \n    public double Convert(double value)\n    {\n        return value * 1.618;\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        Converter conv = new Converter();\n        Console.WriteLine($\"int: {conv.Convert(10)}\");\n        Console.WriteLine($\"long: {conv.Convert(100L)}\");\n        Console.WriteLine($\"float: {conv.Convert(3.14f)}\");\n        Console.WriteLine($\"double: {conv.Convert(2.718)}\");\n    }\n}",
