    id: "cs_poly_6",
    topicId: "cs_polymorphism",
    question: "Demonstrate polymorphism with interfaces.",
    mathSolution: "Interfaces define contracts for polymorphic behavior.",
    codeSolution: "using System;\n\ninterface IPlayable\n{\n    void Play();\n    void Pause();\n    void Stop();\n}\n\nclass MusicPlayer : IPlayable\n{\n    public void Play() => Console.WriteLine(\"Playing music\");\n    public void Pause() => Console.WriteLine(\"Music paused\");\n    public void Stop() => Console.WriteLine(\"Music stopped\");\n}\n\nclass VideoPlayer : IPlayable\n{\n    public void Play() => Console.WriteLine(\"Playing video\");\n    public void Pause() => Console.WriteLine(\"Video paused\");\n    public void Stop() => Console.WriteLine(\"Video stopped\");\n}\n\nclass Program\n{\n    static void Main()\n    {\n        IPlayable[] players = { new MusicPlayer(), new VideoPlayer() };\n        \n        foreach (var player in players)\n        {\n            player.Play();\n            player.Pause();\n            player.Stop();\n            Console.WriteLine();\n        }\n    }\n}",
    hint: "Interfaces enable polymorphism across unrelated classes.",
