    question: "Demonstrate polymorphism with collections (List of base type).",
    mathSolution: "Collections of base type hold derived objects polymorphically.",
    codeSolution: "using System;\nusing System.Collections.Generic;\n\ninterface IShape\n{\n    double GetArea();\n    string GetName();\n}\n\nclass Circle : IShape\n{\n    public double Radius { get; set; }\n    public Circle(double radius) => Radius = radius;\n    public double GetArea() => Math.PI * Radius * Radius;\n    public string GetName() => $\"Circle(r={Radius})\";\n}\n\nclass Rectangle : IShape\n{\n    public double Width { get; set; }\n    public double Height { get; set; }\n    public Rectangle(double w, double h) => (Width, Height) = (w, h);\n    public double GetArea() => Width * Height;\n    public string GetName() => $\"Rectangle({Width}×{Height})\";\n}\n\nclass Triangle : IShape\n{\n    public double Base { get; set; }\n    public double Height { get; set; }\n    public Triangle(double b, double h) => (Base, Height) = (b, h);\n    public double GetArea() => 0.5 * Base * Height;\n    public string GetName() => $\"Triangle(b={Base}, h={Height})\";\n}\n\nclass Program\n{\n    static void Main()\n    {\n        List<IShape> shapes = new List<IShape>\n        {\n            new Circle(5),\n            new Rectangle(4, 6),\n            new Triangle(3, 4),\n            new Circle(3)\n        };\n        \n        double totalArea = 0;\n        foreach (var shape in shapes)\n        {\n            double area = shape.GetArea();\n            totalArea += area;\n            Console.WriteLine($\"{shape.GetName(),-20} Area: {area,8:F2}\");\n        }\n        \n        Console.WriteLine($\"\\nTotal area: {totalArea:F2}\");\n    }\n}",
