    codeSolution: "using System;\n\nclass Calculator\n{\n    public int Add(int a, int b) => a + b;\n    public double Add(double a, double b) => a + b;\n    public string Add(string a, string b) => a + b;\n}\n\nclass Program\n{\n    static void Main()\n    {\n        dynamic calc = new Calculator();\n        \n        // Methods resolved at runtime\n        Console.WriteLine($\"int result: {calc.Add(5, 10)}\");\n        Console.WriteLine($\"double result: {calc.Add(3.5, 2.7)}\");\n        Console.WriteLine($\"string result: {calc.Add(\"Hello \", \"World\")}\");\n        \n        // Dynamic with different types\n        dynamic value1 = 10;\n        dynamic value2 = 20;\n        dynamic sum = value1 + value2;\n        Console.WriteLine($\"Dynamic sum: {sum}\");\n        \n        value1 = \"Hello \";\n        value2 = \"World\";\n        sum = value1 + value2;\n        Console.WriteLine($\"Dynamic concatenation: {sum}\");\n    }\n}",
    hint: "dynamic defers type checking to runtime, enabling flexible polymorphism.",
