    question: "Demonstrate polymorphism with extension methods.",
    mathSolution: "Extension methods provide polymorphic-like behavior.",
    codeSolution: "using System;\n\ninterface IAnimal\n{\n    string Name { get; }\n}\n\nclass Dog : IAnimal\n{\n    public string Name { get; set; }\n}\n\nclass Cat : IAnimal\n{\n    public string Name { get; set; }\n}\n\nstatic class AnimalExtensions\n{\n    public static void Speak(this IAnimal animal)\n    {\n        if (animal is Dog)\n            Console.WriteLine($\"{animal.Name} says: Woof!\");\n        else if (animal is Cat)\n            Console.WriteLine($\"{animal.Name} says: Meow!\");\n        else\n            Console.WriteLine($\"{animal.Name} makes a sound\");\n    }\n    \n    public static string GetSound(this IAnimal animal) => animal switch\n    {\n        Dog => \"Woof!\",\n        Cat => \"Meow!\",\n        _ => \"???\"\n    };\n}\n\nclass Program\n{\n    static void Main()\n    {\n        IAnimal[] animals = \n        {\n            new Dog { Name = \"Buddy\" },\n            new Cat { Name = \"Whiskers\" }\n        };\n        \n        foreach (var animal in animals)\n        {\n            animal.Speak();\n            Console.WriteLine($\"  Sound: {animal.GetSound()}\");\n        }\n    }\n}",
